import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o as e,c as o,a as n,b as p,e as c,f as l}from"./app-d9d82146.js";const i={},u=l(`<h3 id="原型与原型链" tabindex="-1"><a class="header-anchor" href="#原型与原型链" aria-hidden="true">#</a> 原型与原型链？</h3><ol><li>函数的prototype属性: 在定义函数时自动添加的, 默认值是一个空Object对象</li><li>对象的__proto__属性: 创建对象时自动添加的, 默认值为构造函数的prototype属性值</li><li>构造函数、实例、原型对象三者之间的关系</li></ol><blockquote><ul><li>每个构造函数会创建一个<code>prototype</code>属性指向原型对象，这个对象包含了该构造函数的所有实例共享的属性和方法；</li><li>原型对象会有一个<code>constructor</code>属性指回构造函数；</li><li>当我们使用构造函数去创建实例时，实例的<code>__proto__</code>属性就会指向构造函数的原型对象。</li></ul></blockquote><ol start="4"><li>原型链：当访问一个对象的属性时，如果这个对象内部不存在这个属性，那么它就会去它的原型对象里找这个属性，这个原型对象又会有自己的原型，于是就这样一直找下去，也就是原型链的概念。原型链的尽头一般来说都是 <code>Object.prototype</code>，直到<code>Object.prototype的.__proto__==null;</code></li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">Person</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span>
<span class="token keyword">let</span> p <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Person</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token comment">//用构造函数去创建实例时，实例的\`__proto__\`属性就会指向构造函数的原型对象Person.prototype === p.__proto__;</span>
p<span class="token punctuation">.</span>__proto__<span class="token punctuation">;</span> <span class="token comment">// Person.prototype</span>
<span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>constructor<span class="token punctuation">;</span> <span class="token comment">// Person</span>
p<span class="token punctuation">.</span>__proto__<span class="token punctuation">.</span>__proto__<span class="token punctuation">;</span> <span class="token comment">//Object.prototype</span>
<span class="token class-name">Person</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>__proto__<span class="token punctuation">;</span> <span class="token comment">// Object.prototype</span>
<span class="token comment">//一切的函数对象(Object, Function, Array)，都是继承自Function对象;Object对象直接继承自Function对象</span>
Object <span class="token keyword">instanceof</span> <span class="token class-name">Function</span> <span class="token comment">//true Object继承自Function对象，所以他的构造函数是Function</span>
Function <span class="token keyword">instanceof</span> <span class="token class-name">Object</span> <span class="token comment">//true Function.prototype是一个对象，所以他的构造函数是Object</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="对象继承几种方式" tabindex="-1"><a class="header-anchor" href="#对象继承几种方式" aria-hidden="true">#</a> 对象继承几种方式？</h3><ol><li>借用构造函数：<code>Father.call()</code>借用父类构造器复制父类的实例属性给子类；只能继承父类实例的属性和方法，原型上的继承不了。</li><li>原型链继承:<code>Son.prototype = new Parent(); </code> 借用父的实例作为子类的原型，通过构造函数构造产生的对象，可以继承原型的属性和方法；</li><li>组合继承：原型链实现对原型属性方法的基础，构造函数实现父类实例的继承。缺点是调用了两次父类构造函数，生成了两份实例；以及有constructor指向问题。</li><li>寄生式组合继承:</li></ol><blockquote><p>a. 子类如何继承父类的属性？call调用父类函数, 并且修改函数运行时的this指向，将this指向子类的(子类函数里面写<code>Father.call(this, arg1, arg2)</code>)；<br> b. 子类如何继承父类的方法？改变子类的原型对象为父类原型对象（不能直接赋值，<code>Son.prototype = new Father()</code>，子类的constructor再指向子类）；<br> c. 进一步优化就是new Father()改为Object.create(Father.prototype),减少父类的一次调用。（Object.create()将参数(原型对象)作为一个新建的空对象的原型，并返回这个空对象）</p></blockquote><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1 父类</span>
<span class="token keyword">function</span> <span class="token function">Parent</span><span class="token punctuation">(</span><span class="token parameter">name<span class="token punctuation">,</span> age</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>name <span class="token operator">=</span> name
  <span class="token keyword">this</span><span class="token punctuation">.</span>age <span class="token operator">=</span> age
<span class="token punctuation">}</span>
<span class="token class-name">Parent</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">say</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>name<span class="token punctuation">,</span> <span class="token keyword">this</span><span class="token punctuation">.</span>age<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">// 2 子类</span>
<span class="token keyword">function</span> <span class="token function">Son</span><span class="token punctuation">(</span><span class="token parameter">name<span class="token punctuation">,</span> age<span class="token punctuation">,</span> grade</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>grade <span class="token operator">=</span> grade；
  <span class="token comment">// 3 继承父类的属性name, age</span>
  <span class="token function">Parent</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span> 
<span class="token punctuation">}</span>
<span class="token comment">// 4 继承父类的原型方法say</span>
<span class="token class-name">Son</span><span class="token punctuation">.</span>prototype <span class="token operator">=</span> Object<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token class-name">Parent</span><span class="token punctuation">.</span>prototype<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// 5 子类的constructor再指向子类构造函数</span>
<span class="token class-name">Son</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>constructor <span class="token operator">=</span> Son<span class="token punctuation">;</span>
<span class="token comment">// ---验证：子类Son新建实例对象可以使用父类的方法 属性---</span>
<span class="token keyword">let</span> s <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Son</span><span class="token punctuation">(</span><span class="token string">&#39;tom&#39;</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">,</span> <span class="token string">&#39;111&#39;</span><span class="token punctuation">)</span>
s<span class="token punctuation">.</span><span class="token function">say</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//tom 12</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="类与继承" tabindex="-1"><a class="header-anchor" href="#类与继承" aria-hidden="true">#</a> 类与继承</h3><ol><li>ES6 中新增加了类的概念，使用class关键字声明—个类，之后以这个类来实例化对象。<code>class ClassName {}</code></li><li>constructor构造函数：类里面有个<code>constructor</code>函数,可以接受传递过来的参数,同时返回实例对象；constructor()只要new生成实例时,就会自动调用这个函数。</li><li>类中添加方法:直接在类中写方法名和括号即可;</li><li>static 静态成员,给成员属性或成员方法添加<code>static</code>，该成员就成为静态成员，静态成员只能由该类调用。</li><li>类里面的this指向问题：<code>constructor 里面的this指向实例对象, 方法里面的this指向这个方法的调用者</code></li><li>类的继承:使用<code>extends关键字,super关键</code>字用于访问和调用对象父类上的函数。</li><li>类的本质是语法糖。</li></ol><blockquote><p>a. ES6前通过<code>构造函数 + 原型</code>实现面向对象编程。构造函数有原型对象<code>prototype</code>，原型对象里面有 <code>constructor</code>指向构造函数本身；构造函数创建的实例对象有<code>__proto__</code>原型指向构造函数的原型对象<br> b. ES6后通过<code>class</code>实现面向对象编程。类有原型对象<code>prototype</code>，里面也有<code>constructor</code>指向类的本身；类的所有方法都定义在<code>类的prototype</code>上，它创建的实例，里面也有<code> __proto__</code>指向类的原型对象<br> c. ES6 的类其实就是一种语法糖。</p></blockquote><h3 id="扩展运算符-解构-rest参数" tabindex="-1"><a class="header-anchor" href="#扩展运算符-解构-rest参数" aria-hidden="true">#</a> 扩展运算符 解构 rest参数</h3><ol><li>扩展运算符: 用于取出参数对象中所有的可遍历属性，拷贝到当前的对象中,与Obiect.assign()作用类似，属于浅拷贝。<code>let c={..b};//拷贝 let n=[1,2,3]; console.log(...n)//1,2,3</code></li><li>解构: 可以从数组或者对象有针对的拿到想要的数据。<code>let {aa,bb}=f</code></li><li>rest参数: 剩余参数，把多个不定的参数放起来，就是收集多个元素，压缩成一个。剩余参数经常与解构配合使用</li></ol><h3 id="proxy可以实现什么功能" tabindex="-1"><a class="header-anchor" href="#proxy可以实现什么功能" aria-hidden="true">#</a> proxy可以实现什么功能？</h3><ol><li>可以用来自定义对象中的操作。<code>let p = new Proxy(target, handler);</code>target 代表需要添加代理的对象，<code>handler</code>用来自定义对象中的操作，比如可以用来自定义 set 或者 get 函数。</li><li>通过自定义 set 和 get 函数的方式，在原本的逻辑中插入了其他逻辑，实现了在对对象任何属性进行读写时发出通知。Proxy 可以完美监听到任何方式的数据改变，缺陷就是浏览器的兼容性不好。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// proxy:拦截对象属性的任意变化，包括修改添加删除；</span>
<span class="token comment">// reflect:通过对源对象进行操作，作用是底层使用reflect会比较健壮，不容易出现有个错误就导致程序阻塞</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> reactive <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> user <span class="token operator">=</span> <span class="token function">reactive</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&quot;Tom&quot;</span><span class="token punctuation">,</span> <span class="token literal-property property">age</span><span class="token operator">:</span> <span class="token number">25</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// Proxy 代理原始对象</span>
<span class="token keyword">const</span> proxy <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>user<span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token function">get</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> key<span class="token punctuation">,</span> receiver<span class="token punctuation">)</span> <span class="token punctuation">{</span>  <span class="token comment">// 读取时触发</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;读取属性:&quot;</span><span class="token punctuation">,</span> key<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">return</span> Reflect<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> key<span class="token punctuation">,</span> receiver<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">set</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> key<span class="token punctuation">,</span> value<span class="token punctuation">,</span> receiver<span class="token punctuation">)</span> <span class="token punctuation">{</span>  <span class="token comment">// 修改时触发</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;修改属性:&quot;</span><span class="token punctuation">,</span> key<span class="token punctuation">,</span> value<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">const</span> success <span class="token operator">=</span> Reflect<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>target<span class="token punctuation">,</span> key<span class="token punctuation">,</span> value<span class="token punctuation">,</span> receiver<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>success<span class="token punctuation">)</span> <span class="token punctuation">{</span>   <span class="token comment">// 修改成功，通知依赖</span>
      <span class="token function">trigger</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> success<span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="es6模块与commonjs模块有什么异同" tabindex="-1"><a class="header-anchor" href="#es6模块与commonjs模块有什么异同" aria-hidden="true">#</a> ES6模块与CommonJS模块有什么异同？</h3><ol><li>模块化是什么？将程序⽂件依据⼀定规则拆分成多个⽂件，拆分出来每个⽂件就是⼀个模块。模块中的数据都是私有的，模块之间互相隔离。同时也能通过⼀些⼿段，可以把模块内的指定数据“交出去”，供其他模块使⽤。</li><li>有哪些模块化规范？<code>CommonJS(服务端应用广泛)；AMD ；CMD；ES6模块化(浏览器应用广泛)</code></li><li>区别1：导入导出语法对比：CommonJS导出是 <code>module.exports</code>，导入是<code>require</code>；ES6 Module使用<code>export </code>导出,<code>import</code> 引入具体数据。</li><li>区别2：加载时机：CommonJS是运行时动态加载，执行到<code>require()</code>时才加载模块；而ES6 Module是编译时静态分析，代码执行前完成所有<code>import</code>的解析。</li><li>区别3：CommonJS输出的是值的拷贝，一旦输出一个值，模块内部的变化就影响不到这个值；ES6 Module输出的是值的只读引用，不能修改其变量的指针指向。但是原始值变了，import加载的值也会跟着变。因此，ES6模块是动态引用。</li><li>区别4：浏览器支持：CommonJS需要打包工具转换，ES6 Module现代浏览器直接支持，设置<code>&lt;script type=&quot;module&quot;&gt;</code>即可。</li></ol><h3 id="链接" tabindex="-1"><a class="header-anchor" href="#链接" aria-hidden="true">#</a> 链接</h3>`,20),r={href:"https://www.bilibili.com/video/BV14s411E7qf?spm_id_from=333.788.videopod.episodes&vd_source=a3aec2a1dd5f478da3517872d0c61c5c",target:"_blank",rel:"noopener noreferrer"};function d(k,m){const s=t("ExternalLinkIcon");return e(),o("div",null,[u,n("p",null,[n("a",r,[p("尚硅谷JavaScript高级教程(javascript实战进阶)"),c(s)])])])}const _=a(i,[["render",d],["__file","JavaScript的原型与继承.html.vue"]]);export